arguments.file_text:
@* Left sidebar: list of channels *@

<div class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    @foreach (var channel in Channels)
    {
        <ChannelItem Channel="channel"
                     IsActive="channel.Id == ActiveChannelId"
                     OnClick="() => OnSelectChannel.InvokeAsync(channel.Id)" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnSelectChannel { get; set; }
}

@inject IJSRuntime JS

@* Scrollable message list with load-more on scroll to top *@

<div class="message-list" @ref="scrollContainer">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages...</div>
    }
    @if (HasMore)
    {
        <button class="load-more-btn" @onclick="OnLoadMore">Load older messages</button>
    }
    @foreach (var msg in Messages)
    {
        <MessageItem Message="msg"
                     ThreadSummary="GetThreadSummary(msg.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="(emoji) => OnReact.InvokeAsync((msg.Id, emoji))" />
    }
    <div @ref="bottomAnchor"></div>
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference scrollContainer;
    private ElementReference bottomAnchor;
    private int previousCount;

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Auto-scroll to bottom when new messages arrive (not when loading older)
        if (Messages.Count > previousCount && !IsLoadingMore)
        {
            await JS.InvokeVoidAsync("eval", "document.querySelector('.message-list')?.scrollTo(0, document.querySelector('.message-list')?.scrollHeight)");
        }
        previousCount = Messages.Count;
    }
}

@* Main message area: channel header, messages, input *@

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="channel-header">
            <h2># @Channel.Name</h2>
            <span class="channel-description">@Channel.Description</span>
        </div>

        <MessageList Messages="Messages"
                     ThreadSummaries="ThreadSummaries"
                     HasMore="HasMore"
                     IsLoadingMore="IsLoadingMore"
                     OnLoadMore="OnLoadMore"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonLabel="Send"
                      OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="no-channel-selected">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
}

@* Right panel: thread view with original message, replies, and input *@

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="message-header">
                <span class="message-author">@RootMessage.Author</span>
                <span class="message-time">@FormatRelativeTime(RootMessage.SentAt)</span>
            </div>
            <div class="message-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="message-item thread-reply">
                    <div class="message-header">
                        <span class="message-author">@reply.Author</span>
                        <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread..."
                      ButtonLabel="Reply"
                      OnSubmit="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
