arguments.file_text:
@page "/chat"
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="selectedChannelId"
                    OnSelectChannel="SelectChannel" />

    <div class="chat-main @(threadRootMessage is null ? "full-width" : "")">
        <MessageArea Channel="selectedChannel"
                     Messages="messages"
                     ThreadSummaries="threadSummaries"
                     HasMore="hasMore"
                     IsLoadingMore="isLoadingMore"
                     OnLoadMore="LoadOlderMessages"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnSendMessage="SendMessage" />
    </div>

    @if (threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnSendReply="SendThreadReply"
                     OnClose="CloseThread" />
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private int? selectedChannelId;
    private Channel? selectedChannel;

    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];
    private bool hasMore = true;
    private bool isLoadingMore;

    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        threadSummaries = [];
        hasMore = true;

        CloseThread();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        hasMore = loaded.Count == PageSize;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);

        // Update local unread count
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadOlderMessages()
    {
        if (isLoadingMore || !hasMore || selectedChannelId is null) return;

        isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(selectedChannelId.Value, messages.Count, PageSize);
        hasMore = older.Count == PageSize;
        messages.InsertRange(0, older);
        BuildThreadSummaries();
        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannelId.Value, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        var threadMessages = await ChatService.GetThreadAsync(messageId);
        threadReplies = threadMessages.Where(m => m.Id != messageId).ToList();
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannelId is null || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(selectedChannelId.Value, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary
        UpdateThreadSummary(threadRootMessage.Id);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update local state
        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private void BuildThreadSummaries()
    {
        threadSummaries = messages
            .Where(m => m.ReplyToId is null)
            .Select(m =>
            {
                var replies = messages.Where(r => r.ReplyToId == m.Id).ToList();
                return replies.Count > 0
                    ? new ThreadSummary(m.Id, replies.Count, replies.Max(r => r.SentAt))
                    : null;
            })
            .Where(ts => ts is not null)
            .Cast<ThreadSummary>()
            .ToList();
    }

    private void UpdateThreadSummary(int rootMessageId)
    {
        var existing = threadSummaries.FindIndex(t => t.RootMessageId == rootMessageId);
        var summary = new ThreadSummary(rootMessageId, threadReplies.Count, DateTime.UtcNow);
        if (existing >= 0)
            threadSummaries[existing] = summary;
        else
            threadSummaries.Add(summary);
    }
}

