toolArgs.file_text:
/* ===== Chat Layout ===== */

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    color: #1d1c1d;
}

/* ===== Channel Sidebar ===== */

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow-y: auto;
    border-right: 1px solid #522653;
}

.sidebar-title {
    padding: 16px 16px 8px;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    margin: 0;
}

.channel-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 6px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 1px 8px;
    transition: background 0.1s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.1);
}

.channel-item.active {
    background: #1264a3;
    color: #fff;
}

.channel-item.active .channel-desc {
    color: rgba(255, 255, 255, 0.7);
}

.channel-info {
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-width: 0;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-desc {
    font-size: 0.75rem;
    color: #9b8e9c;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
    flex-shrink: 0;
    margin-left: 8px;
}

/* ===== Main Area ===== */

.chat-main {
    width: 55%;
    display: flex;
    flex-direction: column;
    transition: width 0.2s ease;
}

.chat-main.full-width {
    width: 80%;
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    overflow: hidden;
}

.channel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e1e1e1;
    flex-shrink: 0;
}

.channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.channel-description {
    font-size: 0.8rem;
    color: #616061;
    margin-top: 2px;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 1.1rem;
}

/* ===== Message List ===== */

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-indicator {
    text-align: center;
    padding: 8px;
    color: #888;
    font-size: 0.85rem;
}

.load-more-btn {
    display: block;
    margin: 0 auto 12px;
    padding: 6px 16px;
    background: none;
    border: 1px solid #ddd;
    border-radius: 6px;
    cursor: pointer;
    color: #1264a3;
    font-size: 0.85rem;
}

.load-more-btn:hover {
    background: #f8f8f8;
}

/* ===== Message Item ===== */

.message-item {
    position: relative;
    padding: 6px 8px;
    border-radius: 6px;
    margin-bottom: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.9rem;
}

.message-time {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    word-break: break-word;
}

/* ===== Reactions ===== */

.reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #e1e1e1;
    border-radius: 12px;
    background: #f8f8f8;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.1s;
}

.reaction-badge:hover {
    background: #e8e8e8;
    border-color: #1264a3;
}

/* ===== Thread Link ===== */

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 2px 8px;
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

/* ===== Hover Actions ===== */

.message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e1e1e1;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    cursor: pointer;
    border-radius: 4px;
    font-size: 1rem;
}

.action-btn:hover {
    background: #f0f0f0;
}

/* ===== Emoji Picker ===== */

.emoji-picker {
    position: absolute;
    top: -8px;
    right: 80px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e1e1e1;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 11;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    padding: 4px 6px;
    cursor: pointer;
    border-radius: 4px;
}

.emoji-option:hover {
    background: #f0f0f0;
}

/* ===== Message Input ===== */

.message-input {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #e1e1e1;
    flex-shrink: 0;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    font-family: inherit;
    font-size: 0.9rem;
    line-height: 1.4;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #1264a3;
}

.btn-send {
    padding: 8px 20px;
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    font-size: 0.85rem;
    cursor: pointer;
    transition: background 0.15s;
    white-space: nowrap;
}

.btn-send:hover:not(:disabled) {
    background: #006049;
}

.btn-send:disabled {
    background: #ccc;
    cursor: not-allowed;
}

/* ===== Thread Panel ===== */

.thread-panel {
    width: 25%;
    min-width: 280px;
    border-left: 1px solid #e1e1e1;
    display: flex;
    flex-direction: column;
    height: 100vh;
    background: #fff;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e1e1e1;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #f0f0f0;
}

.thread-root-message {
    padding: 12px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e1e1e1;
}

.thread-divider {
    text-align: center;
    padding: 8px;
    font-size: 0.75rem;
    color: #999;
    border-bottom: 1px solid #e1e1e1;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

.thread-reply {
    padding: 6px 0;
}

